#!/usr/bin/env node
/**
 * Regenerates src/data/confusables.generated.ts from the Unicode Consortium's
 * UTS #39 confusables data.
 *
 * Usage:
 *   node scripts/generate-confusables.mjs                # fetch /Public/security/latest/
 *   node scripts/generate-confusables.mjs --version 17.0.0
 *   node scripts/generate-confusables.mjs --file path/to/confusables.txt
 *
 * The generated file is checked in; this script only needs to run when a new
 * Unicode security release ships. A scheduled CI job is the intended caller.
 */
import { readFileSync, writeFileSync, mkdirSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const args = process.argv.slice(2);
const getArg = (name) => {
  const i = args.indexOf(name);
  return i === -1 ? undefined : args[i + 1];
};

async function loadSource() {
  const file = getArg('--file');
  if (file) return readFileSync(file, 'utf8');
  const version = getArg('--version') ?? 'latest';
  const url = `https://www.unicode.org/Public/security/${version}/confusables.txt`;
  const res = await fetch(url);
  if (!res.ok) throw new Error(`GET ${url} -> ${res.status}`);
  return res.text();
}

const source = await loadSource();

const versionMatch = source.match(/^#\s*Version:\s*(\S+)/m);
const dateMatch = source.match(/^#\s*Date:\s*([\d-]+)/m);
if (!versionMatch) throw new Error('No "# Version:" header in confusables.txt');

// Each data line is: <source cp> ; <target cp sequence> ; MA # comment
const entries = [];
for (const line of source.split('\n')) {
  const data = line.split('#')[0].trim();
  if (!data) continue;
  const [from, to, type] = data.split(';').map((s) => s.trim());
  if (type !== 'MA' || !from || !to) continue;
  if (from.includes(' ')) throw new Error(`Multi-codepoint source: ${from}`);
  entries.push(`${from}>${to}`);
}
if (entries.length < 5000) {
  throw new Error(`Suspiciously few entries (${entries.length}) — refusing to write`);
}

const __dirname = dirname(fileURLToPath(import.meta.url));
const outPath = join(__dirname, '..', 'src', 'data', 'confusables.generated.ts');
mkdirSync(dirname(outPath), { recursive: true });

// Packed as "SRC>T1 T2;SRC>T1;…" (hex codepoints) and chunked so no single
// line is unreadably long. Parsed into a Map at module init.
const packed = entries.join(';');
const chunks = packed.match(/.{1,2000}/gs) ?? [];

writeFileSync(
  outPath,
  `// AUTO-GENERATED by scripts/generate-confusables.mjs — DO NOT EDIT.
// Source: UTS #39 confusables.txt (https://www.unicode.org/reports/tr39/)
// Entries: ${entries.length}

export const UNICODE_VERSION = '${versionMatch[1]}';
export const DATA_DATE = '${dateMatch?.[1] ?? 'unknown'}';

export const CONFUSABLES_PACKED =
${chunks.map((c) => `  '${c}'`).join(' +\n')};
`,
);

console.log(`Wrote ${entries.length} mappings (Unicode ${versionMatch[1]}) to ${outPath}`);
